Review this TypeScript connection pool and caching layer for correctness and performance:

```typescript
class ConnectionPool {
  private pool: Connection[] = [];
  private waiting: ((conn: Connection) => void)[] = [];
  private cache: Map<string, { data: any; timestamp: number }> = new Map();
  private maxSize: number;
  private cacheTimeout = 300000; // 5 min

  constructor(maxSize: number) {
    this.maxSize = maxSize;
  }

  async query(sql: string, params: any[]): Promise<any> {
    const cacheKey = sql + JSON.stringify(params);
    const cached = this.cache.get(cacheKey);

    if (cached && Date.now() - cached.timestamp < this.cacheTimeout) {
      return cached.data;
    }

    const conn = await this.getConnection();
    const result = await conn.execute(sql, params);
    this.cache.set(cacheKey, { data: result, timestamp: Date.now() });
    this.releaseConnection(conn);
    return result;
  }

  private async getConnection(): Promise<Connection> {
    if (this.pool.length > 0) {
      return this.pool.pop()!;
    }
    if (this.pool.length < this.maxSize) {
      return new Connection();
    }
    return new Promise(resolve => this.waiting.push(resolve));
  }

  private releaseConnection(conn: Connection) {
    if (this.waiting.length > 0) {
      this.waiting.shift()!(conn);
    } else {
      this.pool.push(conn);
    }
  }
}
```

Review this API gateway handler that coordinates between microservices:

```typescript
import express from 'express';
import axios from 'axios';
import Redis from 'ioredis';

const redis = new Redis();
const app = express();

app.post('/api/checkout', async (req, res) => {
  const { userId, items, paymentToken, promoCode } = req.body;

  // Step 1: Validate promo code
  let discount = 0;
  if (promoCode) {
    const promo = await axios.get(`http://promo-service/validate/${promoCode}`);
    discount = promo.data.discount;
  }

  // Step 2: Check inventory
  const inventory = await axios.post('http://inventory-service/check', { items });
  if (!inventory.data.available) {
    return res.status(400).json({ error: 'Items unavailable' });
  }

  // Step 3: Reserve inventory
  await axios.post('http://inventory-service/reserve', { items, userId });

  // Step 4: Calculate total
  const total = items.reduce((sum, item) => sum + item.price * item.quantity, 0);
  const finalTotal = total - (total * discount / 100);

  // Step 5: Charge payment
  const payment = await axios.post('http://payment-service/charge', {
    userId, amount: finalTotal, token: paymentToken
  });

  // Step 6: Create order
  const order = await axios.post('http://order-service/create', {
    userId, items, total: finalTotal, paymentId: payment.data.id
  });

  // Step 7: Cache order
  await redis.set(`order:${order.data.id}`, JSON.stringify(order.data));

  res.json({ orderId: order.data.id, total: finalTotal });
});
